<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">net_tx</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> net_rx</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> mpsc</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">channel</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">64</span><span style="color:#9399B2;">);</span></span>
